import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.24.0";
import { z as z2 } from "npm:zod@^4.4.3";
var get_product_default = defineTool2({
  name: "get_product",
  title: "Get product details",
  description: "Get full details of a single product from the Pa\xF1alera La Elegancia del Baby catalog by its id, including description, features, brand, price, discount, stock and recommended age.",
  inputSchema: {
    id: z2.string().min(1).describe("Product id (e.g. '1', '2', ...).")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ id }) => {
    const product = getCatalogProductById(id);
    if (!product) {
      return {
        content: [
          { type: "text", text: `No se encontr\xF3 un producto con id '${id}'.` }
        ],
        isError: true
      };
    }
    return {
      content: [{ type: "text", text: JSON.stringify(product, null, 2) }],
      structuredContent: { product }
    };
  }
});

// src/lib/mcp/tools/search-products.ts
import { defineTool as defineTool3 } from "npm:@lovable.dev/mcp-js@0.24.0";
import { z as z3 } from "npm:zod@^4.4.3";
var search_products_default = defineTool3({
  name: "search_products",
  title: "Search products",
  description: "Full-text search across the Pa\xF1alera La Elegancia del Baby catalog. Matches product name, description, brand, category, features, size and recommended age.",
  inputSchema: {
    query: z3.string().min(1).describe("Search text, e.g. 'pa\xF1ales reci\xE9n nacido', 'shampoo', 'caminador'."),
    limit: z3.number().int().positive().optional().describe("Max results to return.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ query, limit }) => {
    const q = query.toLowerCase();
    let items = catalogProducts.filter((p) => {
      const haystack = [
        p.name,
        p.description,
        p.brand,
        p.category,
        p.categoryId,
        p.size ?? "",
        p.age ?? "",
        p.features.join(" ")
      ].join(" ").toLowerCase();
      return haystack.includes(q);
    });
    if (limit) items = items.slice(0, limit);
    const summary = items.map((p) => ({
      id: p.id,
      name: p.name,
      price: p.price,
      category: p.category,
      brand: p.brand,
      age: p.age,
      stock: p.stock
    }));
    return {
      content: [
        {
          type: "text",
          text: `Se encontraron ${summary.length} resultado(s) para "${query}".

${JSON.stringify(summary, null, 2)}`
        }
      ],
      structuredContent: { query, count: summary.length, products: summary }
    };
  }
});

